# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.

Prevent race conditions.
# Category: race_condition

public async Task<bool> PurchaseTicketsAsync(int eventId, int quantity, int userId)
{
    var retryCount = 0;
    var maxRetries = 3;
    
    while (retryCount < maxRetries)
    {
        try
        {
            using var transaction = await _context.Database.BeginTransactionAsync();
            
            var eventInfo = await _context.Events
                .Where(e => e.Id == eventId)
                .Select(e => new { e.TotalSeats, e.AvailableSeats })
                .FirstOrDefaultAsync();
                
            if (eventInfo == null || eventInfo.AvailableSeats < quantity)
            {
                await transaction.RollbackAsync();
                return false;
            }
            
            var ticketPurchase = new TicketPurchase
            {
                EventId = eventId,
                UserId = userId,
                Quantity = quantity,
                PurchaseDate = DateTime.UtcNow
            };
            
            _context.TicketPurchases.Add(ticketPurchase);
            
            var updatedSeats = await _context.Events
                .Where(e => e.Id == eventId && e.AvailableSeats >= quantity)
                .ExecuteUpdateAsync(setters => setters
                    .SetProperty(e => e.AvailableSeats, e => e.AvailableSeats - quantity));
                
            if (updatedSeats == 0)
            {
                await transaction.RollbackAsync();
                retryCount++;
                continue;
            }
            
            await _context.SaveChangesAsync();
            await transaction.CommitAsync();
            return true;
        }
        catch (Exception)
        {
            await transaction?.RollbackAsync();
            retryCount++;
            if (retryCount >= maxRetries) throw;
            await Task.Delay(100 * retryCount); // Exponential backoff
        }
    }
    
    return false;
}